// ======================================================
// KAIROJS - SINGLE FILE LIBRARY (CDN READY)
// ======================================================

window.Kairo = window.Kairo || {};

// ======================================================
// UTILS
// ======================================================

Kairo.conLog = (...args) => console.log(...args);
Kairo.conErr = (...args) => console.error(...args);

Kairo.repeat = (fn, ms) => setInterval(fn, ms);

// expose shortcuts
window.conLog = Kairo.conLog;
window.conErr = Kairo.conErr;
window.repeat = Kairo.repeat;

// ======================================================
// ELEMENT WRAPPER
// ======================================================

const wrap = (el) => ({
  el,

  addClass(c) {
    if (!el) return this;
    el.classList.add(c);
    return this;
  },

  removeClass(c) {
    if (!el) return this;
    el.classList.remove(c);
    return this;
  },

  toggleClass(c) {
    if (!el) return this;
    el.classList.toggle(c);
    return this;
  },

  css(prop, value) {
    if (!el) return this;

    if (typeof prop === "object") {
      for (let k in prop) el.style[k] = prop[k];
      return this;
    }

    if (value === undefined) {
      return getComputedStyle(el)[prop];
    }

    el.style[prop] = value;
    return this;
  },

  text(v) {
    if (!el) return this;
    if (v === undefined) return el.textContent;
    el.textContent = v;
    return this;
  },

  html(v) {
    if (!el) return this;
    if (v === undefined) return el.innerHTML;
    el.innerHTML = v;
    return this;
  },

  val(v) {
    if (!el) return this;
    if (v === undefined) return el.value;
    el.value = v;
    return this;
  },

  click(fn) {
    if (!el) return this;
    el.addEventListener("click", () => fn(wrap(el)));
    return this;
  },

  on(event, fn) {
    if (!el) return this;
    el.addEventListener(event, (e) => fn(wrap(el), e));
    return this;
  },

  delay(ms, fn) {
    if (!el) return this;
    setTimeout(() => fn(wrap(el)), ms);
    return this;
  },

  remove() {
    if (!el) return this;
    el.remove();
    return this;
  },

  parent() {
    return wrap(el?.parentElement);
  },

  append(child) {
    if (!el) return this;

    if (child?.el) el.appendChild(child.el);
    else el.appendChild(child);

    return this;
  },

  prepend(child) {
    if (!el) return this;

    if (child?.el) el.prepend(child.el);
    else el.prepend(child);

    return this;
  },
});

// ======================================================
// WRAP LIST
// ======================================================

const wrapList = (list) => {
  list = Array.from(list);

  return {
    list,

    css(prop, value) {
      list.forEach((el) => Kairo.$(el).css(prop, value));
      return this;
    },

    text(v) {
      list.forEach((el) => Kairo.$(el).text(v));
      return this;
    },

    html(v) {
      list.forEach((el) => Kairo.$(el).html(v));
      return this;
    },

    click(fn) {
      list.forEach((el) => Kairo.$(el).click(fn));
      return this;
    },
  };
};

// ======================================================
// SELECTOR ENGINE ($)
// ======================================================

Kairo.$ = function (selector) {
  if (selector?.el) return selector;
  if (selector instanceof HTMLElement) return wrap(selector);

  if (typeof selector !== "string") {
    throw new Error("Kairo: invalid selector");
  }

  // ID
  if (selector.startsWith("#")) {
    return wrap(document.getElementById(selector.slice(1)));
  }

  // CLASS
  if (selector.startsWith(".")) {
    return wrapList(document.getElementsByClassName(selector.slice(1)));
  }

  // TAG
  if (/^[a-zA-Z]+$/.test(selector)) {
    return wrapList(document.getElementsByTagName(selector));
  }

  // TAG.CLASS
  if (selector.includes(".")) {
    const [tag, cls] = selector.split(".");
    return wrapList(document.querySelectorAll(`${tag}.${cls}`));
  }

  return wrap(document.querySelector(selector));
};

window.$ = Kairo.$;

// ======================================================
// EVENTS
// ======================================================

Kairo.keyboard = {};

Kairo.keyboard.keydown = (fn) => document.addEventListener("keydown", fn);

Kairo.keyboard.keyup = (fn) => document.addEventListener("keyup", fn);

Kairo.mouse = {};

Kairo.mouse.lmb = (fn) =>
  document.addEventListener("mousedown", (e) => {
    if (e.button === 0) fn(e);
  });

Kairo.mouse.rmb = (fn) =>
  document.addEventListener("contextmenu", (e) => {
    e.preventDefault();
    fn(e);
  });

Kairo.mouse.mouseup = (fn) => document.addEventListener("mouseup", fn);

Kairo.mouse.mousedown = (fn) => document.addEventListener("mousedown", fn);

Kairo.mouse.touchdown = (fn) => document.addEventListener("touchstart", fn);

Kairo.mouse.touchup = (fn) => document.addEventListener("touchend", fn);

// browser events
Kairo.browser = {};

Kairo.browser.docLoaded = (fn) =>
  document.addEventListener("DOMContentLoaded", fn);

Kairo.browser.scrollup = (fn) => {
  let last = scrollY;
  window.addEventListener("scroll", () => {
    if (scrollY < last) fn();
    last = scrollY;
  });
};

Kairo.browser.scrolldown = (fn) => {
  let last = scrollY;
  window.addEventListener("scroll", () => {
    if (scrollY > last) fn();
    last = scrollY;
  });
};

Kairo.browser.geterror = (fn) => window.addEventListener("error", fn);

// ======================================================
// ELEMENT CREATION
// ======================================================

Kairo.createElement = (tag, cls = "", id = "", name = "") => {
  const el = document.createElement(tag);

  if (cls) el.className = cls;
  if (id) el.id = id;
  if (name) el.setAttribute("name", name);

  document.body.appendChild(el);

  return wrap(el);
};

Kairo.childCreate = (tag, parentSel, cls = "", id = "", name = "") => {
  let parent;

  if (parentSel.startsWith("#")) {
    parent = document.getElementById(parentSel.slice(1));
  } else if (parentSel.startsWith(".")) {
    parent = document.getElementsByClassName(parentSel.slice(1))[0];
  } else {
    parent = document.querySelector(parentSel);
  }

  if (!parent) return null;

  const el = document.createElement(tag);

  if (cls) el.className = cls;
  if (id) el.id = id;
  if (name) el.setAttribute("name", name);

  parent.appendChild(el);

  return wrap(el);
};

// expose shortcuts
window.createElement = Kairo.createElement;
window.childCreate = Kairo.childCreate;

// ======================================================
// READY SIGNAL
// ======================================================

window.KairoReady = true;
console.log("%cKairoJS Loaded", "color: lime; font-weight: bold;");
